request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name WHERE {
  ?elem vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("APS")))
  OPTIONAL { ?elem rdf:type ?type }
  FILTER( ?type = vocab:tmt%20requirement || ?type = vocab:block || ?type = vocab:view || ?type = vocab:document || ?type = vocab:package )
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name ?body WHERE {
  ?elem vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("The%20APS%20and%20Its%20Role%20in%20TMT")))
  OPTIONAL { ?elem rdf:type ?type }
  OPTIONAL { ?elem vocab:body ?body }
  OPTIONAL { ?elem vocab:ownedElement+ ?child . }
}
LIMIT 25
